CREATE TABLE IF NOT EXISTS managed_domains(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,name text NOT NULL,owner text NOT NULL,registrar text NOT NULL DEFAULT '',status text NOT NULL DEFAULT 'active',expires_at timestamptz,auto_renew boolean NOT NULL DEFAULT true,dns_provider text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,name));CREATE TABLE IF NOT EXISTS managed_certificates(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,domain_id uuid NOT NULL,common_name text NOT NULL,sans jsonb NOT NULL DEFAULT '[]',owner text NOT NULL,issuer text NOT NULL DEFAULT '',serial_number text NOT NULL DEFAULT '',status text NOT NULL,issued_at timestamptz,expires_at timestamptz NOT NULL,key_algorithm text NOT NULL,key_size int NOT NULL,auto_renew boolean NOT NULL,vault_ref text NOT NULL DEFAULT '',last_rotated_at timestamptz,next_rotation_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());CREATE TABLE IF NOT EXISTS certificate_events(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),certificate_id uuid NOT NULL,type text NOT NULL,data jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now());CREATE INDEX IF NOT EXISTS idx_certificate_expiry ON managed_certificates(tenant_id,status,expires_at);CREATE INDEX IF NOT EXISTS idx_certificate_rotation ON managed_certificates(tenant_id,next_rotation_at);
